/**
 * Trailing-window drawdown probe for the BTC/5m diagnostic paper
sandbox (Task #670). Computed over the most recent N closed DS
trades — same trade stream the auto-disable evaluator already
watches, but sliced to the trailing window so a slow drift can be
spotted before it eats through the floor. Field naming is
snake_case to match the rest of the operator-facing DS contract.

 */
export interface DiagnosticSandboxHealth {
  /** False when DS mode is not active, the lane has never been
enabled, or no DS trades have closed yet. The remaining fields
are still populated with safe defaults so the dashboard can
render the policy preview.
 */
  evaluable: boolean;
  label: string;
  coin_id: string;
  timeframe: string;
  /** @nullable */
  btc_version: string | null;
  /** Configured trailing window size (most-recent N closed trades). */
  window_trades: number;
  /** Number of trades actually counted in the trailing window. May
be < `window_trades` early in the lane's life.
 */
  n_trades_observed: number;
  /** Peak-to-trough drawdown of the equity curve over the trailing
window, account-weighted by the DS fixed-position pin (≤ 0).
 */
  trailing_drawdown_pct: number;
  /** Cumulative account-weighted PnL over the trailing window. */
  trailing_pnl_pct: number;
  /** Configured drawdown floor (negative, e.g. -0.05). */
  drawdown_floor_pct: number;
  /** Warning trip line: `floor * warn_fraction` (negative, less
negative than the floor — e.g. -0.04 when floor is -0.05).
 */
  warn_threshold_pct: number;
  /** Fraction of |floor| at which the trailing drawdown is
considered to be eating into the headroom and a refit
should be staged (default 0.8).
 */
  warn_fraction: number;
  /** Distance from the trailing drawdown to the floor:
`trailing_drawdown_pct - drawdown_floor_pct`. Positive ⇒
headroom remaining; ≤ 0 ⇒ floor is at or past breach.
 */
  headroom_pct: number;
  /** True when the trailing drawdown has eaten through
`warn_threshold_pct`. Operators should stage a re-fit before
the auto-disable evaluator trips.
 */
  needs_refit: boolean;
  /** True when the trailing drawdown is at or past the floor. */
  floor_breached: boolean;
  computed_at: string;
}

